import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';
import { SyncCatalogButton } from './_components/SyncCatalogButton';

/**
 * Cached catalog fetch — tagged with "products".
 *
 * Because the result is cached, every-day browsing (read-heavy) never
 * re-queries the upstream data source.  Invalidating the tag (e.g. via
 * a sync action) causes the *next* render to fetch fresh data while the
 * current request still serves the stale snapshot — eventual consistency
 * without blocking operators.
 */
const getCachedCatalog = unstable_cache(
  async () => {
    const products = await getAllProducts();
    return { products, syncedAt: Date.now() };
  },
  ['admin-catalog-products'],
  { tags: ['products'] },
);

function formatTime(ts: number) {
  return Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'medium',
  }).format(ts);
}

