"use server";

import { revalidateTag } from "next/cache";
import { addPost } from "./lib/posts";

export async function createPost(formData: FormData) {
  const title = formData.get("title") as string;
  const body = formData.get("body") as string;

  if (!title || !body) {
    throw new Error("Title and body are required");
  }

  await addPost(title, body);

  // Invalidate the "posts" cache tag so the next page load fetches fresh data
  // This evicts the stale cached "posts" entry from the data cache.
  // The next Server Component render that calls getPosts() will re-execute
  // it and wait for the fresh data — no stale content is served.
  revalidateTag("posts", "hours");
}

