'use client';

import { useActionState } from 'react';
import { createPostAction } from '@/app/actions';

export default function PostForm() {
  const [state, formAction, pending] = useActionState(createPostAction, null);

  return (
    <form action={formAction} style={{ marginBottom: '2rem' }}>
      <div>
        <input
          name="title"
          type="text"
          placeholder="Post title"
          required
          disabled={pending}
          style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem' }}
        />
      </div>
      <div>
        <textarea
          name="content"
          placeholder="Post content"
          required
          rows={4}
          disabled={pending}
          style={{ width: '100%', padding: '0.5rem', marginBottom: '0.5rem' }}
        />
      </div>
      <button type="submit" disabled={pending}>
        {pending ? 'Creating...' : 'Create Post'}
      </button>
      {state?.error && (
        <p style={{ color: '#d32f2f', marginTop: '0.5rem' }}>{state.error}</p>
      )}
      {state?.success && !pending && (
        <p style={{ color: '#2e7d32', marginTop: '0.5rem' }}>
          Post created! The page has been refreshed with fresh data.
        </p>
      )}
    </form>
  );
}


